// Fetch most active stocks for anomaly detection
const symbols = ['SPY', 'QQQ', 'AAPL', 'TSLA', 'NVDA', 'META', 'GOOGL', 'AMZN', 'MSFT', 'AMD'];
const results = [];

for (const symbol of symbols) {
  try {
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${symbol}?interval=5m&range=1d`;
    const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
    const data = await res.json();
    const result = data.chart?.result?.[0];
    if (result) {
      const meta = result.meta;
      const volumes = result.indicators?.quote?.[0]?.volume || [];
      const closes = result.indicators?.quote?.[0]?.close || [];
      const recentVolume = volumes.slice(-3).reduce((a, b) => a + (b || 0), 0) / 3;
      const avgVolume = volumes.slice(-20).reduce((a, b) => a + (b || 0), 0) / Math.max(volumes.slice(-20).filter(v => v).length, 1);
      const volumeRatio = avgVolume > 0 ? recentVolume / avgVolume : 1;
      const priceChange = closes.length > 1 ? ((closes[closes.length-1] - closes[0]) / closes[0]) * 100 : 0;

      results.push({
        symbol,
        currentPrice: meta.regularMarketPrice,
        volumeRatio: volumeRatio,
        recentVolume,
        avgVolume,
        priceChange5min: priceChange,
        isAnomaly: volumeRatio > 2.5 || Math.abs(priceChange) > 1.5
      });
    }
  } catch(e) {}
}

return results.map(r => ({ json: r }));

const allItems = $input.all().map(i => i.json);
const anomalies = allItems.filter(item => item.isAnomaly);

if (anomalies.length === 0) {
  return [{ json: { hasAnomalies: false, count: 0, anomalies: [] } }];
}

const classified = anomalies.map(a => {
  let type = 'VOLUME_SPIKE';
  let description = '';

  if (a.volumeRatio > 5 && Math.abs(a.priceChange5min) > 2) {
    type = 'UNUSUAL_ACTIVITY';
    description = `🚨 Massive volume + price move on ${a.symbol}`;
  } else if (a.volumeRatio > 2.5) {
    type = 'VOLUME_SPIKE';
    description = `⚡ Volume spike on ${a.symbol} (${a.volumeRatio.toFixed(1)}x normal)`;
  } else if (Math.abs(a.priceChange5min) > 1.5) {
    type = 'PRICE_MOVE';
    description = `📊 Sharp 5min move on ${a.symbol}: ${a.priceChange5min.toFixed(2)}%`;
  }

  return { ...a, type, description };
});

return [{ json: { hasAnomalies: true, count: anomalies.length, anomalies: classified } }];
